// JavaScript — three ways to declare variables
const name = "Alice";   // const: cannot be reassigned
let age = 25;           // let: block-scoped, can be reassigned
var city = "Berlin";    // var: old, function-scoped (avoid in modern code)

age = 26;               // OK — let can be reassigned
// name = "Bob";        // ERROR — const cannot be reassigned

console.log(`${name} is ${age} years old`);
// Output: Alice is 26 years old

